from typing import Any

# Survivorship rule registry: (entity_domain, attribute) -> source_priority
SURVIVORSHIP_RULES: dict[tuple[str, str], list[str]] = {
    ("product", "list_price"):       ["erp", "crm"],    # ERP is authoritative for price
    ("product", "description"):     ["crm", "erp"],    # CRM owns marketing copy
    ("product", "stock_qty"):        ["erp"],           # Only ERP has inventory
    ("customer", "legal_name"):      ["crm", "erp"],
    ("customer", "billing_address"): ["erp", "crm"],
    ("employee", "job_title"):        ["hrms", "ldap"],
    ("employee", "email"):            ["ldap", "hrms"],
    ("policy", "content"):            ["confluence"],   # Single system of record
}

def apply_survivorship(
    domain: str,
    attribute: str,
    source_values: dict[str, Any],   # {source_name: value}
) -> tuple[Any, str]:                # (winning_value, winning_source)
    """Return the winning attribute value and the name of its source system."""
    priority = SURVIVORSHIP_RULES.get((domain, attribute), list(source_values.keys()))
    for source in priority:
        if source in source_values and source_values[source] is not None:
            return source_values[source], source
    raise ValueError(f"No authoritative value found for {domain}.{attribute}")

from dataclasses import dataclass

@dataclass
class RetrievedChunk:
    text: str
    mdm_id: str
    golden_record_version: int
    entity_domain: str
    source_ids: dict[str, str]

def filter_stale_chunks(
    chunks: list[RetrievedChunk],
    mdm_hub,
    max_version_lag: int = 2,
) -> tuple[list[RetrievedChunk], list[RetrievedChunk]]:
    """Separate chunks into current and stale based on golden record version lag."""
    current, stale = [], []
    for chunk in chunks:
        current_version = mdm_hub.get_current_version(chunk.mdm_id)
        lag = current_version - chunk.golden_record_version
        if lag <= max_version_lag:
            current.append(chunk)
        else:
            stale.append(chunk)
    return current, stale

def build_rag_context(
    chunks: list[RetrievedChunk],
    mdm_hub,
) -> str:
    current, stale = filter_stale_chunks(chunks, mdm_hub)
    context_parts = [c.text for c in current]
    if stale:
        stale_ids = ", ".join(c.mdm_id for c in stale)
        context_parts.append(
            f"[NOTE: {len(stale)} chunk(s) for entities {stale_ids} "
            "may be outdated. Verify before citing.]"
        )
    return "\n\n".join(context_parts)
